+// transactionalReloader serializes reloads and retains the last fully applied
+// configuration so a partially applied reload can be undone.
+type transactionalReloader struct {
+	mu        sync.Mutex
+	statePath string
+	logger    *slog.Logger
+	knownGood *config.Config
+	status    web.ReloadStatus
+}
+
+func newTransactionalReloader(statePath string, logger *slog.Logger) *transactionalReloader {
+	r := &transactionalReloader{statePath: statePath, logger: logger, status: emptyReloadStatus()}
+	b, err := os.ReadFile(statePath)
+	if err != nil {
+		return r
+	}
+	if err := json.Unmarshal(b, &r.status); err != nil {
+		logger.Warn("Ignoring corrupt transactional reload status", "filename", statePath, "err", err)
+		r.status = emptyReloadStatus()
+	}
+	return r
+}
+
+func emptyReloadStatus() web.ReloadStatus {
+	return web.ReloadStatus{LastReloadSuccessful: false, ErrorCategory: "none", AppliedReloaders: []string{}, ReloaderTimingsMS: map[string]float64{}}
+}
+
+func (r *transactionalReloader) Status() web.ReloadStatus {
+	r.mu.Lock()
+	defer r.mu.Unlock()
+	return cloneReloadStatus(r.status)
+}
+
+func cloneReloadStatus(s web.ReloadStatus) web.ReloadStatus {
+	s.AppliedReloaders = append([]string(nil), s.AppliedReloaders...)
+	s.ReloaderTimingsMS = make(map[string]float64, len(s.ReloaderTimingsMS))
+	for k, v := range s.ReloaderTimingsMS {
+		s.ReloaderTimingsMS[k] = v
+	}
+	return s
+}
+
+func (r *transactionalReloader) Reload(filename string, enableExemplarStorage bool, logger *slog.Logger, noStep *safePromQLNoStepSubqueryInterval, callback func(bool), rls ...reloader) error {
+	r.mu.Lock()
+	defer r.mu.Unlock()
+
+	conf, err := config.LoadFile(filename, agentMode, logger)
+	if err != nil {
+		// The initial load is not a reload attempt. Once a good configuration is
+		// available, record parse/load failures for operators.
+		if r.knownGood != nil {
+			r.finish(web.ReloadStatus{LastReloadID: time.Now().UTC().Format(time.RFC3339Nano), ErrorCategory: "load_error", ErrorMessage: fmt.Sprintf("couldn't load configuration (--config.file=%q): %v", filename, err), AppliedReloaders: []string{}, ReloaderTimingsMS: map[string]float64{}})
+		}
+		callback(false)
+		return fmt.Errorf("couldn't load configuration (--config.file=%q): %w", filename, err)
+	}
+	if enableExemplarStorage && conf.StorageConfig.ExemplarsConfig == nil {
+		conf.StorageConfig.ExemplarsConfig = &config.DefaultExemplarsConfig
+	}
+
+	// Startup establishes the rollback target but is not itself reported as a
+	// reload attempt or persisted.
+	initial := r.knownGood == nil
+	result := emptyReloadStatus()
+	result.LastReloadID = time.Now().UTC().Format(time.RFC3339Nano)
+	for _, rl := range rls {
+		start := time.Now()
+		err := rl.reloader(conf)
+		result.ReloaderTimingsMS[rl.name] = float64(time.Since(start)) / float64(time.Millisecond)
+		if err != nil {
+			result.ErrorCategory = "apply_error"
+			result.ErrorMessage = err.Error()
+			result.FailedReloader = rl.name
+			if len(result.AppliedReloaders) > 0 && !initial {
+				result.RollbackAttempted = true
+				for _, rollback := range rls {
+					if rollbackErr := rollback.reloader(r.knownGood); rollbackErr != nil {
+						result.ErrorCategory = "rollback_error"
+						result.ErrorMessage = fmt.Sprintf("reload failed in %s: %v; rollback failed in %s: %v", rl.name, err, rollback.name, rollbackErr)
+						result.RollbackSuccessful = false
+						break
+					}
+					result.RollbackSuccessful = true
+				}
+			}
+			if !initial {
+				r.finish(result)
+			}
+			callback(false)
+			return fmt.Errorf("failed to apply configuration in %s: %w", rl.name, err)
+		}
+		result.AppliedReloaders = append(result.AppliedReloaders, rl.name)
+	}
+
+	r.knownGood = conf
+	updateGoGC(conf, logger)
+	noStep.Set(conf.GlobalConfig.EvaluationInterval)
+	callback(true)
+	if !initial {
+		result.LastReloadSuccessful = true
+		result.ErrorCategory = "none"
+		r.finish(result)
+	}
+	return nil
+}
+
+func (r *transactionalReloader) finish(status web.ReloadStatus) {
+	r.status = status
+	b, err := json.Marshal(status)
+	if err != nil {
+		r.logger.Error("Failed to marshal transactional reload status", "err", err)
+		return
+	}
+	if err := os.MkdirAll(filepath.Dir(r.statePath), 0o755); err != nil {
+		r.logger.Error("Failed to create transactional reload status directory", "err", err)
+		return
+	}
+	tmp := r.statePath + ".tmp"
+	if err := os.WriteFile(tmp, b, 0o644); err == nil {
+		err = os.Rename(tmp, r.statePath)
+	}
+	if err != nil {
+		r.logger.Error("Failed to persist transactional reload status", "filename", r.statePath, "err", err)
+	}
+}
